.status-indicator.success {
  color: var(--color-success);
}
.status-indicator.success::before {
  content: "✓";
}

.status-indicator.error {
  color: var(--color-error);
}
.status-indicator.error::before {
  content: "✕";
}

import { test, expect } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';

const routes = ['/', '/pricing', '/login'];

for (const r of routes) {
  test(`a11y: ${r}`, async ({ page }) => {
    await page.goto(r);
    const results = await new AxeBuilder({ page })
      .withTags(['wcag2a', 'wcag2aa', 'wcag21aa', 'wcag22aa'])
      .analyze();
    expect(results.violations, JSON.stringify(results.violations, null, 2)).toEqual([]);
  });
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

.skip-link {
  position: absolute;
  top: -40px;
  left: 0;
  background: #0066cc;
  color: #ffffff;
  padding: 0.5rem 1rem;
  z-index: 100;
}

.skip-link:focus {
  top: 0;
}

// Icon button with label
<button aria-label="Close dialog">
  <CloseIcon aria-hidden="true" />
</button>

// Toggle button
<button
  aria-pressed={isPressed}
  onClick={() => setPressed(!isPressed)}
>
  {isPressed ? 'Mute' : 'Unmute'}
</button>

// Button with loading state
<button disabled={loading} aria-busy={loading}>
  {loading ? (
    <>
      <span className="visually-hidden">Loading...</span>
      <Spinner aria-hidden="true" />
    </>
  ) : (
    'Submit'
  )}
</button>

import { useEffect, useRef } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

export function Modal({ isOpen, onClose, title, children }: ModalProps) {
  const dialogRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    if (!isOpen) return;

    // Store previous focus
    previousFocusRef.current = document.activeElement as HTMLElement;

    // Focus first focusable element
    const focusable = dialogRef.current?.querySelector<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    focusable?.focus();

    // Trap focus
    const trapFocus = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      const focusableElements = dialogRef.current?.querySelectorAll<HTMLElement>(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
      );
      if (!focusableElements || focusableElements.length === 0) return;
      const first = focusableElements[0];
      const last = focusableElements[focusableElements.length - 1];
      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
      }
    };

    // Handle Escape key
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose();
      } else {
        trapFocus(e);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    document.body.style.overflow = 'hidden';

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.body.style.overflow = '';
      previousFocusRef.current?.focus();
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <>
      <div className="modal-backdrop" onClick={onClose} aria-hidden="true" />
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-title"
        className="modal"
      >
        <h2 id="modal-title">{title}</h2>
        {children}
        <button onClick={onClose}>Close</button>
      </div>
    </>
  );
}

// Form with accessibility features
<form aria-labelledby="form-title">
  <h2 id="form-title">Contact Us</h2>

  <label htmlFor="name">Full Name</label>
  <input
    id="name"
    aria-required="true"
    aria-invalid={errors.name ? "true" : "false"}
    aria-describedby={errors.name ? "name-error" : undefined}
  />
  {errors.name && (
    <span id="name-error" role="alert">{errors.name}</span>
  )}

  <div role="status" aria-live="polite" aria-atomic="true">
    {statusMessage}
  </div>

  <div role="alert" aria-live="assertive">
    {errorMessage}
  </div>

  <nav aria-label="Main">...</nav>
  <nav aria-label="Footer">...</nav>

  <div
    role="button"
    tabIndex={0}
    aria-pressed={isPressed}
    onClick={handleClick}
    onKeyDown={(e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleClick();
      }
    }}
  >
    Toggle Feature
  </div>
</form>

function TabList({ tabs, activeTab, onSelect }) {
  const [focusIndex, setFocusIndex] = useState(0);
  const tabRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const handleKeyDown = (e: React.KeyboardEvent, index: number) => {
    let newIndex = index;

    switch (e.key) {
      case 'ArrowRight': newIndex = (index + 1) % tabs.length; break;
      case 'ArrowLeft': newIndex = (index - 1 + tabs.length) % tabs.length; break;
      case 'Home': newIndex = 0; break;
      case 'End': newIndex = tabs.length - 1; break;
      default: return;
    }

    e.preventDefault();
    setFocusIndex(newIndex);
    tabRefs.current[newIndex]?.focus();
  };

  return (
    <div role="tablist">
      {tabs.map((tab, index) => (
        <button
          key={tab.id}
          ref={(el) => (tabRefs.current[index] = el)}
          role="tab"
          aria-selected={activeTab === tab.id}
          aria-controls={`panel-${tab.id}`}
          tabIndex={focusIndex === index ? 0 : -1}
          onClick={() => onSelect(tab.id)}
          onKeyDown={(e) => handleKeyDown(e, index)}
        >
          {tab.label}
        </button>
      ))}
    </div>
  );
}

// Jest + Testing Library
import { render, screen } from '@testing-library/react';
import { axe, toHaveNoViolations } from 'jest-axe';

expect.extend(toHaveNoViolations);

describe('Accessibility', () => {
  it('should have no accessibility violations', async () => {
    const { container } = render(<MyComponent />);
    const results = await axe(container);
    expect(results).toHaveNoViolations();
  });

  it('should have proper heading hierarchy', () => {
    render(<Page />);
    const headings = screen.getAllByRole('heading');
    expect(headings[0]).toHaveAttribute('aria-level', '1');
  });

  it('should have accessible form labels', () => {
    render(<ContactForm />);
    const emailInput = screen.getByLabelText(/email/i);
    expect(emailInput).toBeInTheDocument();
    expect(emailInput).toHaveAttribute('type', 'email');
  });

  it('should announce errors to screen readers', async () => {
    render(<ContactForm />);
    await userEvent.click(screen.getByRole('button', { name: /submit/i }));

    const alert = screen.getByRole('alert');
    expect(alert).toHaveTextContent(/email is required/i);
  });

  it('should be keyboard navigable', async () => {
    render(<Navigation />);

    await userEvent.tab();
    expect(screen.getByRole('link', { name: /home/i })).toHaveFocus();

    await userEvent.tab();
    expect(screen.getByRole('link', { name: /products/i })).toHaveFocus();
  });
});
